[BusinessEvents(classStr(PurchInvoiceBusinessEventContract), "PurchInvoiceGenerated", "Fires when a Purchase Order Invoice is posted", ModuleAxapta::PurchaseOrder)]
public final class PurchInvoiceBusinessEvent extends BusinessEventsBase
{
    private VendInvoiceJour invoiceJour;

}

Method.Source:
private VendInvoiceJour parmInvoiceJour(VendInvoiceJour _invoiceJour = invoiceJour)
{
    invoiceJour = _invoiceJour;
    return invoiceJour;
}

public static PurchInvoiceBusinessEvent newFromVendInvoiceJour(VendInvoiceJour _invoiceJour)
{
    PurchInvoiceBusinessEvent businessEvent = new PurchInvoiceBusinessEvent();
    businessEvent.parmInvoiceJour(_invoiceJour);
    return businessEvent;
}
